// Parse MarketTime order confirmation email
const email = $input.first().json;
const subject = email.subject || '';
const body = email.text || email.html || '';

// Extract order number from subject
const orderMatch = subject.match(/Order Confirmation #(\d+)/);
const orderNumber = orderMatch ? orderMatch[1] : null;

if (!orderNumber) {
  throw new Error('Could not extract order number from subject: ' + subject);
}

// Extract customer info
const customerNameMatch = body.match(/Customer:\s*([^\n]+)/);
const customerEmailMatch = body.match(/Email:\s*([^\n]+)/);
const orderDateMatch = body.match(/Order Date:\s*([^\n]+)/);

const customerName = customerNameMatch ? customerNameMatch[1].trim() : 'Unknown';
const customerEmail = customerEmailMatch ? customerEmailMatch[1].trim() : null;
const orderDate = orderDateMatch ? orderDateMatch[1].trim() : new Date().toISOString().split('T')[0];

// Extract line items
// Expected format:
// Items:
// - SKU: ACME-12345, Qty: 2, Vendor: Acme Products
// - SKU: BETA-789, Qty: 1, Vendor: Beta Supplies

const itemsSection = body.match(/Items:([\s\S]*?)(?:Total:|$)/);
const itemsText = itemsSection ? itemsSection[1] : '';

const lineItemRegex = /SKU:\s*([^,]+),\s*Qty:\s*(\d+)(?:,\s*Vendor:\s*([^\n]+))?/gi;
const items = [];
let match;

while ((match = lineItemRegex.exec(itemsText)) !== null) {
  items.push({
    sku: match[1].trim(),
    quantity: parseInt(match[2]),
    vendor: match[3] ? match[3].trim() : 'Unknown'
  });
}

if (items.length === 0) {
  throw new Error('No line items found in email body');
}

// Create standardized order object
const order = {
  order_id: `MT-${orderNumber}`,
  source: 'markettime',
  customer_name: customerName,
  customer_email: customerEmail,
  order_date: orderDate,
  items: items,
  total_items: items.length,
  total_quantity: items.reduce((sum, item) => sum + item.quantity, 0),
  raw_email_subject: subject,
  raw_email_from: email.from,
  parsed_at: new Date().toISOString()
};

return [{ json: order }];

// Validate parsed order data
const order = $input.first().json;
const errors = [];

// Required fields validation
if (!order.order_id) errors.push('Missing order_id');
if (!order.customer_email) errors.push('Missing customer_email');
if (!order.items || order.items.length === 0) errors.push('No items in order');

// Email validation
if (order.customer_email && !order.customer_email.match(/^[^\s@]+@[^\s@]+\.[^\s@]+$/)) {
  errors.push('Invalid customer email format');
}

// SKU validation
for (const item of order.items || []) {
  if (!item.sku) errors.push(`Item missing SKU: ${JSON.stringify(item)}`);
  if (!item.quantity || item.quantity < 1) errors.push(`Invalid quantity for SKU ${item.sku}`);
}

if (errors.length > 0) {
  return [{
    json: {
      ...order,
      validation_failed: true,
      validation_errors: errors,
      error_message: errors.join('; ')
    }
  }];
}

return [{
  json: {
    ...order,
    validation_passed: true
  }
}];

// Handle parsing/validation errors
const failedOrder = $input.first().json;
const originalEmail = $node['IMAP Email Monitor'].json;

return [{
  json: {
    error_type: 'order_parsing_failed',
    order_id: failedOrder.order_id || 'UNKNOWN',
    customer_email: failedOrder.customer_email || 'UNKNOWN',
    validation_errors: failedOrder.validation_errors || [],
    email_subject: originalEmail.subject,
    email_from: originalEmail.from,
    email_date: originalEmail.date,
    timestamp: new Date().toISOString(),
    action_required: 'Manual review and processing needed'
  }
}];

// Handle emails that don't match MarketTime pattern
const email = $input.first().json;

return [{
  json: {
    skipped: true,
    reason: 'Not a MarketTime order confirmation',
    email_from: email.from,
    email_subject: email.subject,
    timestamp: new Date().toISOString()
  }
}];
